#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
using namespace std;
template <typename T> inline void rd(T &x)
{
	char ch=getchar();x=0;while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')x=x*10+(ch^48),ch=getchar();
}
const int Mod=1e9+7;
template <typename T> inline T qpow(T a,int b){T res(1);while(b){if(b&1)res=res*a;a=a*a;b=b>>1;}return res;}
struct Int
{
	long long a;inline Int(long long x=0){a=x>Mod?x%Mod:x;}
	inline Int operator + (const Int &x)const{int tmp=a+x.a;return Int(tmp>Mod?tmp-Mod:tmp);}
	inline Int operator - (const Int &x)const{int tmp=a-x.a;return Int(tmp<0?tmp+Mod:tmp);}
	inline Int operator * (const Int &x)const{return Int(a*x.a%Mod);}
	inline Int operator / (const Int &x)const{return Int(a*(qpow(x,Mod-2).a)%Mod);}
	inline void rd()
	{
		a=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
		while(ch<='9'&&ch>='0')a=(a*10+(ch^48))%Mod,ch=getchar();
	}
	inline void pt(char ch=-1)
	{
		int stk[10],top=0,qwq=a;
		while(qwq>9)stk[++top]=qwq%10,qwq/=10;putchar(qwq+'0');
		while(top)putchar(stk[top--]+'0');if(~ch)putchar(ch);
	}
};
int main()
{
	int n,m;rd(n);rd(m);if(n>m)swap(n,m);
	switch(n)
	{
		case 1:qpow(Int(2),m).pt('\n');break;
		case 2:(Int(4)*qpow(Int(3),m-1)).pt('\n');break;
		case 3:(Int(112)*qpow(Int(3),m-3)).pt('\n');break;
		default:
		{
			if(m==n){(((Int(83)*qpow(Int(8),n))+(Int(5)*qpow(Int(2),n+7)))/Int(384)).pt('\n');}
			else (((Int(83)*qpow(Int(8),n)+qpow(Int(2),n+8))*qpow(Int(3),m-n-1))/Int(128)).pt('\n');
		}
	}
}
